<span class="line"><span style="color:#ABB2BF;">    color: </span><span style="color:#56B6C2;">oklch</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">80</span><span style="color:#E06C75;">%</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">0.15</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">30</span><span style="color:#E06C75;">deg</span><span style="color:#ABB2BF;"> / </span><span style="color:#D19A66;">0.8</span><span style="color:#ABB2BF;">); </span><span style="color:#7F848E;font-style:italic;">/* 半透明暖橙 */</span></span>
